import "../styles/UploadForm.css";
import { useState } from "react";
import ResultCard from "./ResultCard";
import { useDropzone } from "react-dropzone";

function UploadForm() {
  const [image, setImage] = useState(null);
  const [weight, setWeight] = useState("");
  const [cmPerPixel, setCmPerPixel] = useState("0.038");
  const [result, setResult] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  // Drag & Drop / Click Upload
  const onDropImage = (acceptedFiles) => {
    const file = acceptedFiles[0];

    if (file) {
      setImage(file);
      setImagePreview(URL.createObjectURL(file));
      setError("");
    }
  };

  const {
    getRootProps,
    getInputProps,
  } = useDropzone({
    onDrop: onDropImage,
    accept: {
      "image/*": [],
    },
    multiple: false,
  });

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!image) {
      setError("Please upload a fish image.");
      return;
    }

    setError("");
    setLoading(true);

    // Dummy data (replace with backend later)
    setTimeout(() => {
      setResult({
        generated_mask:
          "https://via.placeholder.com/400x250.png?text=Generated+Mask",

        length_cm: 28.4,
        thickness_cm: 6.2,
        perimeter_cm: 52.8,
        area_cm2: 135.2,
        volume_proxy_cm3: 840.1,
        predicted_weight_g: 1250,
      });

      setLoading(false);
    }, 2000);
  };

  const removeImage = () => {
    setImage(null);
    setImagePreview(null);
    setResult(null);
  };

  return (
    <div className="container">
      <form onSubmit={handleSubmit}>
        <label>Upload Fish Image</label>

        <div {...getRootProps()} className="dropzone">
          <input {...getInputProps()} />

          <p>Drag & Drop Fish Image Here</p>
          <span>or click to browse</span>
        </div>

        <label>Camera Calibration (cm/pixel)</label>

        <input
          type="number"
          step="0.001"
          value={cmPerPixel}
          onChange={(e) => setCmPerPixel(e.target.value)}
          placeholder="0.038"
        />

        <small className="input-hint">
          Example: 0.038 cm/pixel
        </small>

        <label>Actual Weight (Optional)</label>

        <input
          type="number"
          placeholder="Enter actual weight in grams"
          value={weight}
          onChange={(e) => setWeight(e.target.value)}
        />

        <div className="preview-container">
          {imagePreview && (
            <div className="preview-card">
              <h4>Fish Image</h4>

              <img src={imagePreview} alt="Fish" />

              <button
                type="button"
                className="remove-btn"
                onClick={removeImage}
              >
                Remove
              </button>
            </div>
          )}
        </div>

        {error && <p className="error">{error}</p>}

        <button type="submit">
          {loading ? "Estimating..." : "Estimate Weight"}
        </button>
      </form>

      <ResultCard result={result} />
    </div>
  );
}

export default UploadForm;
